    title="Figure 1: Proportion of AI vs. Non-AI Job Postings (Lightcast 2024)",
    hole=0.45, color_discrete_sequence=["#3498db", "#e74c3c"])
fig.update_traces(textposition='inside', textinfo='percent+label')
fig.show()
```

