state_cat = df.groupby(['state_name', 'job_category']).size().reset_index(name='count')
top15 = df['state_name'].value_counts().head(15).index
state_top = state_cat[state_cat['state_name'].isin(top15)]

fig = px.bar(state_top, x='count', y='state_name', color='job_category',
    orientation='h', barmode='group',
    title="Figure 2: Top 15 States — AI vs. Non-AI Job Postings",
    labels={'count': 'Number of Postings', 'state_name': 'State'},
    color_discrete_map={'AI-Related': '#3498db', 'Non-AI': '#e74c3c'})
fig.update_layout(
    yaxis=dict(categoryorder='total ascending', automargin=True),
    height=650,
    width=1000,
    margin=dict(l=160, r=40, t=80, b=60)
