## 5.2 Market Demand from Lightcast Data

::: {#market-demand .cell execution_count=16}
``` {.python .cell-code code-summary="Skill demand from AI vs Non-AI postings"}
skill_demand_ai, skill_demand_nonai = {}, {}

for cat, d in [('AI-Related', skill_demand_ai), ('Non-AI', skill_demand_nonai)]:
    subset = df[df['job_category'] == cat]
    total = len(subset)
    sk = subset['skills_name'].explode()
    sk = sk[sk != '']
    for skill, count in sk.value_counts().head(30).items():
        d[skill] = round(count / total * 100, 1)

# Combined demand (average)
market_demand = {}
for skill in df_skills.columns:
    market_demand[skill] = round((skill_demand_ai.get(skill, 0) + skill_demand_nonai.get(skill, 0)) / 2, 1)
