## 5.3 Gap Analysis

::: {#gap .cell execution_count=17}
``` {.python .cell-code code-summary="Team vs Market gap analysis"}
team_avg = df_skills.mean()
team_pct = (team_avg / 5 * 100).round(1)

comp = pd.DataFrame({
    'Skill': list(df_skills.columns),
    'Team (%)': [team_pct[s] for s in df_skills.columns],
    'Market Demand (%)': [market_demand.get(s, 0) for s in df_skills.columns]
})
comp['Gap'] = comp['Market Demand (%)'] - comp['Team (%)']
comp = comp.sort_values('Gap', ascending=False)

fig = go.Figure()
fig.add_trace(go.Bar(name='Market Demand', y=comp['Skill'], x=comp['Market Demand (%)'],
    orientation='h', marker_color='#e74c3c'))
fig.add_trace(go.Bar(name='Team Proficiency', y=comp['Skill'], x=comp['Team (%)'],
    orientation='h', marker_color='#2ecc71'))
