# 6. Predictive Modeling

## 6.1 KMeans Clustering

**Goal**: Segment postings using ONET codes, state, and salary to examine how AI vs. non-AI jobs naturally cluster.

::: {#kmeans .cell execution_count=19}
``` {.python .cell-code code-summary="KMeans clustering with elbow and silhouette"}
from sklearn.preprocessing import LabelEncoder, StandardScaler
from sklearn.cluster import KMeans
from sklearn.metrics import silhouette_score

le_dict = {}
cluster_feats = []

for col in ['state_name', 'onet_name']:
    if col in df.columns:
        le = LabelEncoder()
        df[f'{col}_enc'] = le.fit_transform(df[col].fillna('Unknown').astype(str))
        cluster_feats.append(f'{col}_enc')
        le_dict[col] = le

if 'salary' in df.columns:
    cluster_feats.append('salary')
cluster_feats.append('is_ai')

df['is_ai_int'] = df['is_ai'].astype(int)
feat_map = {'is_ai': 'is_ai_int'}
actual_feats = [feat_map.get(f, f) for f in cluster_feats]

df_cl = df[actual_feats].dropna()
print(f"Clustering: {len(df_cl):,} rows, features: {actual_feats}")

scaler = StandardScaler()
X_sc = scaler.fit_transform(df_cl)

inertias, sils = [], []
for k in range(2, 11):
    km = KMeans(n_clusters=k, random_state=42, n_init=10)
    labs = km.fit_predict(X_sc)
    inertias.append(km.inertia_)
    sils.append(silhouette_score(X_sc, labs, sample_size=min(5000, len(X_sc))))

fig = go.Figure()
fig.add_trace(go.Scatter(x=list(range(2,11)), y=inertias, mode='lines+markers', name='Inertia'))
fig.update_layout(title="Figure 14: Elbow Method", xaxis_title="K", yaxis_title="Inertia", height=300)
fig.show()

fig2 = go.Figure()
fig2.add_trace(go.Scatter(x=list(range(2,11)), y=sils, mode='lines+markers',
    name='Silhouette', line=dict(color='#2ecc71')))
fig2.update_layout(title="Figure 15: Silhouette Score by K", xaxis_title="K", yaxis_title="Score", height=300)
fig2.show()

opt_k = list(range(2,11))[np.argmax(sils)]
print(f"Optimal K = {opt_k} (silhouette = {max(sils):.3f})")

km_final = KMeans(n_clusters=opt_k, random_state=42, n_init=10)
df_cl['cluster'] = km_final.fit_predict(X_sc)

cl_sum = df_cl.groupby('cluster').agg(
    count=('is_ai_int','size'), ai_count=('is_ai_int','sum')).reset_index()
cl_sum['ai_pct'] = (cl_sum['ai_count']/cl_sum['count']*100).round(1)

fig3 = px.bar(cl_sum, x='cluster', y='count', color='ai_pct', text='ai_pct',
    title=f"Figure 16: Cluster Sizes & AI Concentration (K={opt_k})",
    labels={'count':'Postings','cluster':'Cluster','ai_pct':'AI %'}, color_continuous_scale='Blues')
fig3.update_traces(texttemplate='%{text}% AI', textposition='outside')
fig3.update_layout(height=400)
fig3.show()

print("\nCluster Summary:")
display(cl_sum)
```

