## 6.3 Classification: Predicting AI vs. Non-AI

**Target**: `is_ai_int` (binary) | **Features**: state, ONET, salary

::: {#classification .cell execution_count=21}
``` {.python .cell-code code-summary="Logistic Regression and Random Forest classification"}
from sklearn.linear_model import LogisticRegression
from sklearn.ensemble import RandomForestClassifier
from sklearn.metrics import accuracy_score, f1_score, confusion_matrix, classification_report

clf_feats = [f for f in actual_feats if f != 'is_ai_int']
df_clf = df_cl[clf_feats + ['is_ai_int']].dropna()
X_c = df_clf[clf_feats]; y_c = df_clf['is_ai_int']
X_tr_c, X_te_c, y_tr_c, y_te_c = train_test_split(X_c, y_c, test_size=0.2, random_state=42, stratify=y_c)

sc = StandardScaler()
X_tr_s = sc.fit_transform(X_tr_c); X_te_s = sc.transform(X_te_c)

# Logistic Regression
log = LogisticRegression(random_state=42, max_iter=1000).fit(X_tr_s, y_tr_c)
yp_log = log.predict(X_te_s)

# Random Forest
rfc = RandomForestClassifier(n_estimators=100, max_depth=10, random_state=42, n_jobs=-1)
rfc.fit(X_tr_c, y_tr_c)
yp_rfc = rfc.predict(X_te_c)

print("Classification Results:")
display(pd.DataFrame({
    'Model': ['Logistic Regression', 'Random Forest'],
    'Accuracy': [f'{accuracy_score(y_te_c, yp_log):.4f}', f'{accuracy_score(y_te_c, yp_rfc):.4f}'],
    'F1 Score': [f'{f1_score(y_te_c, yp_log):.4f}', f'{f1_score(y_te_c, yp_rfc):.4f}']
}))

print("\nRandom Forest — Classification Report:")
print(classification_report(y_te_c, yp_rfc, target_names=['Non-AI', 'AI-Related']))

# Confusion matrices
for name, preds in [('Logistic Regression', yp_log), ('Random Forest', yp_rfc)]:
    cm = confusion_matrix(y_te_c, preds)
    fig = px.imshow(cm, text_auto=True, x=['Non-AI','AI-Related'], y=['Non-AI','AI-Related'],
        title=f"Figure: {name} — Confusion Matrix", color_continuous_scale='Blues',
        labels=dict(x='Predicted', y='Actual'))
    fig.update_layout(height=320, coloraxis_showscale=False)
    fig.show()

# Feature importance
imp_c = pd.DataFrame({'Feature': clf_feats, 'Importance': rfc.feature_importances_}).sort_values('Importance')
fig = px.bar(imp_c, x='Importance', y='Feature',
    title="Figure: Feature Importance — AI Classification (Random Forest)",
    color='Importance', color_continuous_scale='Teal')
fig.update_layout(coloraxis_showscale=False, height=300)
fig.show()
